def lcs_length(a, b):
    # compute LCS length of normalized strings
    a = norm_ar(a)
    b = norm_ar(b)
    n, m = len(a), len(b)
    # Use dynamic programming O(nm) - fine for this length
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            temp=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=temp
    return dp[m]

def lcs_ratio(a,b):
    l = lcs_length(a,b)
    denom = max(len(norm_ar(a)), len(norm_ar(b)))
    return (l/denom) if denom>0 else 0.0

